def test_install_rule_requires_user_only(tmp_path: Path) -> None:
    preview = _make_preview(tmp_path)
    rule_dir, manifest_path = _isolated_dirs(tmp_path)

    report = run_install_rule(
        str(preview), user_only=False, dry_run=True, confirm_install=False,
        rule_dir=rule_dir, manifest_path=manifest_path,
    )

    assert report.passed is False
    assert any("--user-only" in e for e in report.errors)


