# ---------------------------------------------------------------------------
# install-rule: confirmed install writes only under isolated root
# ---------------------------------------------------------------------------

def test_install_rule_confirmed_install_writes_rule_and_manifest(tmp_path: Path) -> None:
    preview = _make_preview(tmp_path)
    rule_dir, manifest_path = _isolated_dirs(tmp_path)

    report = run_install_rule(
        str(preview), user_only=True, dry_run=False, confirm_install=True,
        rule_dir=rule_dir, manifest_path=manifest_path,
    )

    assert report.passed is True
    assert report.dry_run is False
    assert report.install_id
    assert report.rule_id.startswith("pipetune-rule-")
    # Rule file written under isolated rule_dir
    assert rule_dir.exists()
    installed_files = list(rule_dir.glob("90-pipetune-*.lua"))
    assert len(installed_files) == 1
    # Manifest written
    assert manifest_path.exists()
    entries = load_manifest(manifest_path)
    assert len(entries) == 1
    assert entries[0].install_id == report.install_id
    assert entries[0].status == "active"


