# ---------------------------------------------------------------------------
# rollback-rule: dry-run writes nothing
# ---------------------------------------------------------------------------

def test_rollback_rule_dry_run_writes_nothing(tmp_path: Path) -> None:
    rule_dir, manifest_path = _isolated_dirs(tmp_path)
    preview = _make_preview(tmp_path)

    install_report = run_install_rule(
        str(preview), user_only=True, dry_run=False, confirm_install=True,
        rule_dir=rule_dir, manifest_path=manifest_path,
    )
    install_id = install_report.install_id
    installed_files_before = list(rule_dir.glob("*.lua"))

    report = run_rollback_rule(install_id, dry_run=True, confirm_rollback=False, manifest_path=manifest_path)

    assert report.passed is True
    assert report.dry_run is True
    # File still present after dry-run
    assert list(rule_dir.glob("*.lua")) == installed_files_before
    # Manifest entry still active
    entries = load_manifest(manifest_path)
    assert any(e.install_id == install_id and e.status == "active" for e in entries)


# ---------------------------------------------------------------------------
# rollback-rule: confirmed rollback removes file and updates manifest
# ---------------------------------------------------------------------------

def test_rollback_rule_confirmed_removes_file_and_updates_manifest(tmp_path: Path) -> None:
    rule_dir, manifest_path = _isolated_dirs(tmp_path)
    preview = _make_preview(tmp_path)

    install_report = run_install_rule(
        str(preview), user_only=True, dry_run=False, confirm_install=True,
        rule_dir=rule_dir, manifest_path=manifest_path,
    )
    install_id = install_report.install_id

    report = run_rollback_rule(install_id, dry_run=False, confirm_rollback=True, manifest_path=manifest_path)

    assert report.passed is True
    assert not list(rule_dir.glob("*.lua"))
    entries = load_manifest(manifest_path)
    assert any(e.install_id == install_id and e.status == "rolled_back" for e in entries)


def test_rollback_rule_handles_already_missing_file(tmp_path: Path) -> None:
    rule_dir, manifest_path = _isolated_dirs(tmp_path)
    preview = _make_preview(tmp_path)

    install_report = run_install_rule(
        str(preview), user_only=True, dry_run=False, confirm_install=True,
        rule_dir=rule_dir, manifest_path=manifest_path,
    )
    install_id = install_report.install_id
    for f in rule_dir.glob("*.lua"):
        f.unlink()

    report = run_rollback_rule(install_id, dry_run=False, confirm_rollback=True, manifest_path=manifest_path)

    assert report.passed is True
    entries = load_manifest(manifest_path)
    assert any(e.install_id == install_id and e.status == "rolled_back" for e in entries)
    assert any("already missing" in w for w in report.warnings)


