def test_cli_install_rule_dry_run(tmp_path: Path, monkeypatch, capsys) -> None:
    preview = _make_preview(tmp_path)
    rule_dir, manifest_path = _isolated_dirs(tmp_path)

    from pipetune.wireplumber import install as inst_mod, paths as paths_mod

    monkeypatch.setattr(inst_mod, "get_wireplumber_rule_dir", lambda: rule_dir)
    monkeypatch.setattr(inst_mod, "get_manifest_path", lambda: manifest_path)

    exit_code = cli.main([
        "wireplumber", "install-rule", str(preview),
        "--user-only", "--dry-run",
    ])
    out = capsys.readouterr().out

    assert exit_code == 0
    assert "Dry" in out or "dry" in out
    assert "No service was restarted" in out


