# ---------------------------------------------------------------------------
# Safety: no system write, no service restart, no routing
# ---------------------------------------------------------------------------

def test_install_confirmed_does_not_write_outside_isolated_root(tmp_path: Path) -> None:
    preview = _make_preview(tmp_path)
    rule_dir, manifest_path = _isolated_dirs(tmp_path)

    report = run_install_rule(
        str(preview), user_only=True, dry_run=False, confirm_install=True,
        rule_dir=rule_dir, manifest_path=manifest_path,
    )

    assert report.passed is True
    installed = Path(report.destination_path)
    assert str(installed).startswith(str(rule_dir))


def test_no_systemctl_or_routing_calls_in_install_modules() -> None:
    import inspect
    from pipetune.wireplumber import install, rollback, state
    for module in (install, rollback, state):
        src = inspect.getsource(module)
        assert "systemctl" not in src, f"systemctl found in {module.__name__}"
        assert "wpctl set-default" not in src, f"wpctl set-default found in {module.__name__}"
        assert "pactl set-default-sink" not in src
        assert "pactl set-card-profile" not in src
